// Bootstrap palette installer. Fetches the template + route catalog,
// renders subflow definitions, and POSTs them to Node-RED's own admin
// API so they appear as palette nodes without an Import step.
const fs = global.get('fs');
const https = global.get('https');
const http = global.get('http');
const urlMod = global.get('url');
const userDir = global.get('userDir') || '/data';
const port = global.get('port') || 1880;
const baseUrl = global.get('baseUrl') || '';
const credsPath = userDir + '/clusterra-creds.json';

const PRIMITIVES = new Set(['clusterra-api', 'clusterra-watch-job', 'clusterra-init']);
const MANAGED_BY_ENTRYPOINT = new Set(['clusterra-bootstrap-tab', 'boot-init-instance', 'boot-debug']);

function waitForCreds(maxMs) {
    return new Promise((resolve, reject) => {
        const deadline = Date.now() + maxMs;
        (function tick() {
            try { return resolve(JSON.parse(fs.readFileSync(credsPath, 'utf8'))); }
            catch (e) {
                if (Date.now() > deadline) return reject(new Error('creds file not present after ' + maxMs + 'ms: ' + e.message));
                setTimeout(tick, 2000);
            }
        })();
    });
}

let creds;
function apiGet(p) {
    return new Promise((resolve, reject) => {
        const u = new urlMod.URL(creds.api_url + p);
        const lib = u.protocol === 'https:' ? https : http;
        const req = lib.request({
            method: 'GET',
            hostname: u.hostname,
            port: u.port || (u.protocol === 'https:' ? 443 : 80),
            path: u.pathname + u.search,
            headers: { 'Authorization': 'Bearer ' + creds.auth_token, 'Accept': 'application/json' }
        }, (res) => {
            let buf = '';
            res.setEncoding('utf8');
            res.on('data', (c) => buf += c);
            res.on('end', () => {
                if (res.statusCode >= 400) return reject(new Error(p + ' ' + res.statusCode + ': ' + buf));
                try { resolve(JSON.parse(buf)); } catch (e) { reject(e); }
            });
        });
        req.on('error', reject);
        req.end();
    });
}

function adminReq(method, path, body, extraHeaders) {
    return new Promise((resolve, reject) => {
        const headers = Object.assign({
            'Accept': 'application/json',
            'Node-RED-API-Version': 'v2'
        }, extraHeaders || {});
        let payload;
        if (body !== undefined) {
            payload = JSON.stringify(body);
            headers['Content-Type'] = 'application/json';
            headers['Content-Length'] = Buffer.byteLength(payload);
        }
        const req = http.request({
            method, hostname: '127.0.0.1', port, path: baseUrl + path, headers
        }, (res) => {
            let buf = '';
            res.setEncoding('utf8');
            res.on('data', (c) => buf += c);
            res.on('end', () => {
                if (res.statusCode >= 400) return reject(new Error(method + ' ' + path + ' ' + res.statusCode + ': ' + buf));
                try { resolve(buf ? JSON.parse(buf) : {}); } catch (e) { resolve({}); }
            });
        });
        req.on('error', reject);
        if (payload) req.write(payload);
        req.end();
    });
}

// Render a launch subflow. For preset rows (parent_id set), env vars are
// drawn from the parent's parameter list with defaults overridden by the
// preset's static_values + schema_values; the submit targets the parent's
// template_id. The console does the same — preset is UI prefill, parent
// owns the renderable Job/Script.
function renderLaunchSubflow(t, tplById) {
    const sid = 'clusterra-launch-' + t.id;
    let baseParams = t.parameters || [];
    let targetTemplateId = t.id;
    const staticVals = t.static_values || {};
    const schemaVals = t.schema_values || {};
    if (t.parent_id) {
        const parent = tplById[t.parent_id];
        if (!parent) return [];
        baseParams = parent.parameters || [];
        targetTemplateId = parent.id;
    }
    const env = baseParams.map(p => {
        let def = p.default;
        if (Object.prototype.hasOwnProperty.call(staticVals, p.name)) {
            def = staticVals[p.name];
        }
        if (p.name === 'pipeline_params_json' && Object.keys(schemaVals).length > 0) {
            let existing = {};
            if (typeof def === 'string' && def.trim()) {
                try { existing = JSON.parse(def); } catch (_) { existing = {}; }
            }
            def = JSON.stringify(Object.assign(existing, schemaVals));
        }
        const valueType = p.type === 'int' ? 'num' : (p.type === 'bool' ? 'bool' : 'str');
        return {
            name: p.name,
            type: valueType,
            value: def !== undefined && def !== null ? String(def) : '',
            ui: {
                label: { en: p.label || p.name },
                type: p.options ? 'select' : (p.type === 'bool' ? 'checkbox' : 'input'),
                opts: p.options
                    ? { opts: p.options.map(o => ({ l: { en: String(o) }, v: String(o) })) }
                    : { types: ['str','num','bool'] }
            }
        };
    });
    const buildId = sid + '-build';
    const callId = sid + '-call';
    const extractId = sid + '-extract';
    const buildFunc = 'const params = {};\n' + baseParams.map(p =>
        "params['" + p.name + "'] = env.get('" + p.name + "');"
    ).join('\n') + '\nmsg.method = "POST";\nmsg.path = "/v1/clusters/{cluster_id}/jobs/submit";\nmsg.body = { template_id: "' + targetTemplateId + '", params: params };\nreturn msg;';
    // Sub-categorize presets by their `pipeline_repo` so e.g. all sarek
    // presets cluster under "Clusterra · Sarek" instead of one giant
    // "Preset" bucket. Falls back to a generic preset category when no
    // pipeline_repo static value is set.
    let category = 'Clusterra · Launch';
    if (t.parent_id) {
        const repo = (staticVals.pipeline_repo || '');
        const slug = String(repo).split('/').pop();
        if (slug) {
            category = 'Clusterra · ' + slug.charAt(0).toUpperCase() + slug.slice(1);
        } else {
            category = 'Clusterra · Preset';
        }
    }
    return [
        { id: sid, type: 'subflow', name: t.name || t.id,
          info: t.description || ('Launch ' + t.id),
          category: category,
          in: [{ x: 60, y: 60, wires: [{ id: buildId }] }],
          out: [{ x: 720, y: 60, wires: [{ id: extractId, port: 0 }] }],
          env: env, color: '#87A980' },
        { id: buildId, type: 'function', z: sid, name: 'build payload',
          func: buildFunc, outputs: 1, x: 220, y: 60, wires: [[callId]] },
        { id: callId, type: 'subflow:clusterra-api', z: sid, name: 'submit',
          x: 420, y: 60, wires: [[extractId]] },
        { id: extractId, type: 'function', z: sid, name: 'extract job_id',
          func: 'const b = msg.payload || {};\nmsg.job_id = b.job_id || (b.job && b.job.id);\nreturn msg;',
          outputs: 1, x: 600, y: 60, wires: [[]] }
    ];
}

function actionCategory(path) {
    // Coarse REST-resource grouping. Each branch is its own collapsible
    // palette section. Order matters — `/accounting/` falls under Jobs
    // since it's just historical jobs.
    if (path.indexOf('/jobs') >= 0 || path.indexOf('/accounting/') >= 0) return 'Clusterra · Jobs';
    if (path.indexOf('/events') >= 0) return 'Clusterra · Events';
    if (path.indexOf('/storage/') >= 0 || path.indexOf('/storage') === path.length - 8) return 'Clusterra · Storage';
    if (path.indexOf('/sessions') >= 0) return 'Clusterra · Sessions';
    if (path.indexOf('/presets') >= 0) return 'Clusterra · Presets';
    if (path.indexOf('/templates') >= 0) return 'Clusterra · Templates';
    return 'Clusterra · Cluster';
}
function renderActionSubflow(r) {
    const sid = 'clusterra-' + r.name.replace(/_/g, '-');
    const setId = sid + '-set';
    const callId = sid + '-call';
    const setFunc = 'msg.method = "' + r.method + '";\nmsg.path = "' + r.path + '";\n' + (r.stream ? 'msg.stream = true;\n' : '') + 'return msg;';
    return [
        { id: sid, type: 'subflow', name: r.name,
          info: r.method + ' ' + r.path + (r.stream ? ' (SSE)' : ''),
          category: actionCategory(r.path),
          in: [{ x: 60, y: 60, wires: [{ id: setId }] }],
          out: [{ x: 540, y: 60, wires: [{ id: callId, port: 0 }] }],
          env: [], color: '#87A980' },
        { id: setId, type: 'function', z: sid, name: 'set request',
          func: setFunc, outputs: 1, x: 220, y: 60, wires: [[callId]] },
        { id: callId, type: 'subflow:clusterra-api', z: sid, name: 'call',
          x: 420, y: 60, wires: [[]] }
    ];
}

function hashOf(s) {
    let h = 5381;
    for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) | 0;
    return h.toString(16);
}

(async () => {
    try {
        node.status({ fill: 'yellow', shape: 'dot', text: 'waiting for creds…' });
        creds = await waitForCreds(120000);
        node.status({ fill: 'yellow', shape: 'dot', text: 'fetching catalog…' });
        const tplResp = await apiGet('/v1/templates');
        const routesResp = await apiGet('/v1/api-routes');
        const allTemplates = tplResp.templates || [];
        const tplById = Object.fromEntries(allTemplates.map(t => [t.id, t]));
        const templates = allTemplates.filter(t => t.kind !== 'interactive' && t.ready);
        const routes = routesResp.routes || [];

        const managed = [];
        for (const t of templates) managed.push(...renderLaunchSubflow(t, tplById));
        for (const r of routes) managed.push(...renderActionSubflow(r));
        const managedSubflowIds = new Set(managed.filter(n => n.type === 'subflow').map(n => n.id));

        // Idempotency guard: skip the deploy if we've already installed this
        // exact catalog. Without this the POST /flows below would trigger a
        // reload that re-fires our once:true inject, causing an infinite
        // redeploy loop on every restart.
        const hash = hashOf(JSON.stringify(managed));
        const lastHash = global.get('clusterra_palette_hash');

        node.status({ fill: 'yellow', shape: 'dot', text: 'reading flows…' });
        const current = await adminReq('GET', '/flows');
        const currentFlows = Array.isArray(current) ? current : (current.flows || []);
        const currentRev = Array.isArray(current) ? undefined : current.rev;
        const haveAll = managedSubflowIds.size > 0 && [...managedSubflowIds].every(
            id => currentFlows.some(n => n.id === id && n.type === 'subflow')
        );
        if (lastHash === hash && haveAll) {
            node.status({ fill: 'green', shape: 'dot', text: 'palette up to date (' + managedSubflowIds.size + ' subflows)' });
            node.send({ payload: { ok: true, skipped: true, subflows: managedSubflowIds.size } });
            return;
        }

        // Strip prior managed subflows + their child nodes. Keep the three
        // primitives + entrypoint-managed bootstrap nodes + everything else
        // the user has authored.
        const isPriorManaged = (n) => {
            const id = n.id || '';
            const z = n.z || '';
            if (PRIMITIVES.has(id) || MANAGED_BY_ENTRYPOINT.has(id)) return false;
            if (PRIMITIVES.has(z) || MANAGED_BY_ENTRYPOINT.has(z)) return false;
            if (id.startsWith('clusterra-launch-')) return true;
            if (z && z.startsWith('clusterra-launch-')) return true;
            if (id.startsWith('clusterra-') && !PRIMITIVES.has(id)) return true;
            if (z && z.startsWith('clusterra-') && !PRIMITIVES.has(z)) return true;
            return false;
        };
        const preserved = currentFlows.filter(n => !isPriorManaged(n));
        const merged = preserved.concat(managed);

        node.status({ fill: 'yellow', shape: 'dot', text: 'installing palette…' });
        const body = currentRev !== undefined ? { flows: merged, rev: currentRev, deploymentType: 'full' } : merged;
        await adminReq('POST', '/flows', body, { 'Node-RED-Deployment-Type': 'full' });
        global.set('clusterra_palette_hash', hash);

        node.status({ fill: 'green', shape: 'dot', text: 'palette ready (' + managedSubflowIds.size + ' subflows)' });
        node.send({ payload: { ok: true, installed: managedSubflowIds.size } });
    } catch (e) {
        node.error('palette install failed: ' + e.message, { payload: e.message });
        node.status({ fill: 'red', shape: 'dot', text: 'install failed' });
    }
})();
return null;
